const https = require('https');
function postGas(url, payload) {
  return new Promise((resolve,reject) => {
    const body = JSON.stringify(payload);
    const u = new URL(url);
    const req = https.request({ hostname:u.hostname, path:u.pathname+u.search, method:'POST', headers:{'Content-Type':'application/json','Content-Length':Buffer.byteLength(body)} }, (res) => {
      if (res.statusCode===302 && res.headers.location) {
        res.resume();
        const r2=https.request(res.headers.location,(r2res)=>{let d='';r2res.on('data',c=>d+=c);r2res.on('end',()=>{try{resolve(JSON.parse(d));}catch(e){reject(new Error('GAS parse:'+d.substring(0,200)));}})});
        r2.on('error',reject);r2.end();return;
      }
      let d='';res.on('data',c=>d+=c);res.on('end',()=>{try{resolve(JSON.parse(d));}catch(e){reject(new Error('GAS:'+d.substring(0,200)));}}); 
    });
    req.on('error',reject);req.setTimeout(60000,()=>{req.destroy();reject(new Error('GAS timeout'));});req.write(body);req.end();
  });
}
